const row = $input.first()?.json || {};
const sharedUrl = String(row['Shared Url'] || '');
const githubUrl = String(row['Github Url'] || '');

const extractDriveId = (url) => {
  const text = String(url || '');
  const fileMarker = '/file/d/';
  const fileIndex = text.indexOf(fileMarker);
  if (fileIndex !== -1) {
    return text.slice(fileIndex + fileMarker.length).split('/')[0].split('?')[0];
  }
  const queryMatch = text.match(/[?&]id=([^&]+)/i);
  if (queryMatch?.[1]) return queryMatch[1];
  const genericMarker = '/d/';
  const genericIndex = text.indexOf(genericMarker);
  if (genericIndex !== -1) {
    return text.slice(genericIndex + genericMarker.length).split('/')[0].split('?')[0];
  }
  return '';
};

const extractGithub = (url) => {
  try {
    const parsed = new URL(url);
    const parts = parsed.pathname.split('/').filter(Boolean);
    const blobIndex = parts.indexOf('blob');
    if (blobIndex < 2) return { github_owner: '', github_repo: '', github_path: '' };
    return {
      github_owner: decodeURIComponent(parts[0]),
      github_repo: decodeURIComponent(parts[1]),
      github_path: decodeURIComponent(parts.slice(blobIndex + 2).join('/')),
    };
  } catch {
    return { github_owner: '', github_repo: '', github_path: '' };
  }
};

return [{
  json: {
    ...row,
    shared_url: sharedUrl,
    drive_file_id: extractDriveId(sharedUrl),
    ...extractGithub(githubUrl),
  },
}];

const rows = $input.all();
const workflow = $('Wait').item.json;
const row = rows.find((item) => item.json && item.json.row_number !== undefined)?.json;
const hasRealRow = Boolean(row);
const trackedUpdatedAt = hasRealRow ? String(row['Last Modified'] || '') : '';
const workflowUpdatedAt = String(workflow.updatedAt || '');
return [{
  json: {
    notFound: !hasRealRow,
    needsUpdate: !hasRealRow || trackedUpdatedAt !== workflowUpdatedAt,
  },
}];

